// @n8n-evol-I:primitive — exempt from pure-function discipline
// Centralise stream/group/consumer naming and key shapes. All downstream
// HTTP nodes read $('Build Pop Context').first().json — stable across the
// branching graph.
//
// callerExecutionId: prefer the caller-supplied id over $execution.id. Inside
// queue_pop (which runs as an executeWorkflow sub-workflow), $execution.id is
// the SUB-workflow's id, NOT the parent consumer's. The permit sidecar must
// record the parent's id so error_handler_queue_cleanup's ownership filter
// can match (errorTrigger fires with the parent's failed-execution id).
// Producers/consumers wired via add_queue_*_to_workflow.py pass this through
// as `caller_execution_id`. Standalone callers can omit it and accept the
// $execution.id fallback (cleanup will not match in that case).
const stream = $json.stream;
if (!stream) throw new Error("queue_pop: 'stream' required");
const group = $json.group || `${stream}-cg`;
const consumer = $json.consumer || `${stream}-c-${$execution.id}`;
const maxConcurrency = typeof $json.max_concurrency === 'number' ? $json.max_concurrency : 1;
const maxRetries = typeof $json.max_retries === 'number' ? $json.max_retries : 3;
const dlqEnabled = $json.dlq_enabled === true;
const batchSize = typeof $json.batch_size === 'number' ? $json.batch_size : 1;
const claimIdleMs = typeof $json.claim_idle_ms === 'number' ? $json.claim_idle_ms : 60000;
const callerExecutionId = (typeof $json.caller_execution_id === 'string' && $json.caller_execution_id.length > 0)
  ? $json.caller_execution_id
  : String($execution.id);
const inflightKey = `q:${stream}:inflight`;
const dlqStream = `${stream}-dlq`;
return [{
  json: {
    stream, group, consumer, maxConcurrency, maxRetries, dlqEnabled,
    batchSize, claimIdleMs, inflightKey, dlqStream,
    callerExecutionId,
    executionId: $execution.id,
    workflowId: $workflow.id,
    workflowName: $workflow.name,
  },
}];

// @n8n-evol-I:primitive — exempt from pure-function discipline
// XAUTOCLAIM returns: [next_cursor, [[id, [field, val, ...]], ...], deleted_ids]
// Upstash REST returns it under $json.result. If the messages array is empty,
// no PEL'd messages were stale enough to claim — we'll fall through to
// XREADGROUP for fresh delivery.
const resp = $json;
const raw = resp ? resp.result : null;
let has_claimed = false;
let message_id = null;
let fields_arr = null;
if (Array.isArray(raw) && Array.isArray(raw[1]) && raw[1].length > 0) {
  const first = raw[1][0];
  if (Array.isArray(first) && first.length >= 2) {
    has_claimed = true;
    message_id = first[0];
    fields_arr = first[1];
  }
}
return [{ json: { has_claimed, message_id, fields_arr, claimed: has_claimed } }];

// @n8n-evol-I:primitive — exempt from pure-function discipline
// XREADGROUP returns null on empty (no messages) or [[stream, [[id,
// [field, val, ...]], ...]]] on hit. Upstash REST nests under .result.
const resp = $json;
const raw = resp ? resp.result : null;
let has_message = false;
let message_id = null;
let fields_arr = null;
if (Array.isArray(raw) && raw.length > 0 && Array.isArray(raw[0]) && Array.isArray(raw[0][1]) && raw[0][1].length > 0) {
  const first = raw[0][1][0];
  if (Array.isArray(first) && first.length >= 2) {
    has_message = true;
    message_id = first[0];
    fields_arr = first[1];
  }
}
return [{ json: { has_claimed: has_message, message_id, fields_arr, claimed: false } }];

// @n8n-evol-I:primitive — exempt from pure-function discipline
// Unify both branches: $json carries either Parse Claim Result or Parse Read
// Result depending on which path fed us. Decode the flat [k,v,k,v,...] fields
// array into a payload object + enqueued_at. delivery_count is intentionally
// not set here — it is filled in by the downstream 'XPENDING Lookup' +
// 'Check DLQ Threshold' pair, which reads the authoritative count from Redis
// (XPENDING ... IDLE 0 <id> <id> 1 returns [id, consumer, idle, dc]).
const src = $json;
const has_message = src && (src.has_claimed === true || src.has_message === true);
if (!has_message) {
  return [{ json: { has_message: false, claimed: false } }];
}
const fields = Array.isArray(src.fields_arr) ? src.fields_arr : [];
let payload = null;
let enqueued_at = null;
for (let i = 0; i + 1 < fields.length; i += 2) {
  const k = fields[i];
  const v = fields[i + 1];
  if (k === 'payload') {
    try { payload = JSON.parse(v); } catch (e) { payload = v; }
  } else if (k === 'enqueued_at') {
    enqueued_at = v;
  }
}
const claimed = src.claimed === true;
return [{ json: {
  has_message: true,
  message_id: src.message_id,
  payload,
  enqueued_at,
  claimed,
}}];

// @n8n-evol-I:primitive — exempt from pure-function discipline
const ctx = $('Build Pop Context').first().json;
return [{ json: { empty: true, at_capacity: false, dlq_routed: false, stream: ctx.stream, group: ctx.group } }];

// @n8n-evol-I:primitive — exempt from pure-function discipline
// Pull authoritative delivery_count from XPENDING result (detailed form
// returns [[id, consumer, idle_ms, delivery_count]]). On the rare race where
// the message was XACK'd between Merge Message and now, XPENDING returns []
// and we treat it as a fresh delivery (count=1) — defensive fallback.
const ctx = $('Build Pop Context').first().json;
const merge = $('Merge Message').first().json;
const pendingResp = $json;
let delivery_count = 1;
const raw = pendingResp ? pendingResp.result : null;
if (Array.isArray(raw) && raw.length > 0 && Array.isArray(raw[0]) && raw[0].length >= 4) {
  const dcRaw = raw[0][3];
  const parsed = typeof dcRaw === 'number' ? dcRaw : parseInt(dcRaw, 10);
  if (!Number.isNaN(parsed) && parsed > 0) delivery_count = parsed;
}
const overLimit = ctx.dlqEnabled === true && delivery_count > ctx.maxRetries;
return [{ json: { ...merge, delivery_count, ctx_inflight_key: ctx.inflightKey, ctx_dlq_stream: ctx.dlqStream, should_dlq: overLimit } }];

// @n8n-evol-I:primitive — exempt from pure-function discipline
const ctx = $('Build Pop Context').first().json;
const msg = $('Check DLQ Threshold').first().json;
return [{ json: {
  empty: false, at_capacity: false, dlq_routed: true,
  stream: ctx.stream, group: ctx.group, original_message_id: msg.message_id,
  dlq_stream: ctx.dlqStream, delivery_count: msg.delivery_count,
}}];

// @n8n-evol-I:primitive — exempt from pure-function discipline
const ctx = $('Build Pop Context').first().json;
const msg = $('Check DLQ Threshold').first().json;
const incrResp = $json;
const raw = incrResp ? incrResp.result : 0;
const count = typeof raw === 'number' ? raw : parseInt(raw, 10) || 0;
const overCap = count > ctx.maxConcurrency;
return [{ json: { ...msg, inflight_count: count, over_capacity: overCap } }];

// @n8n-evol-I:primitive — exempt from pure-function discipline
const ctx = $('Build Pop Context').first().json;
const gate = $('Capacity Gate').first().json;
return [{ json: {
  empty: false, at_capacity: true, dlq_routed: false,
  stream: ctx.stream, group: ctx.group, inflight_count: gate.inflight_count,
  max_concurrency: ctx.maxConcurrency, message_id: gate.message_id,
}}];

// @n8n-evol-I:primitive — exempt from pure-function discipline
const ctx = $('Build Pop Context').first().json;
const gate = $('Capacity Gate').first().json;
return [{ json: {
  empty: false, at_capacity: false, dlq_routed: false,
  stream: ctx.stream, group: ctx.group,
  message_id: gate.message_id,
  payload: gate.payload,
  enqueued_at: gate.enqueued_at,
  delivery_count: gate.delivery_count,
  claimed: gate.claimed,
  permit_held: true,
  inflight_count: gate.inflight_count,
}}];
